mapper.select:
SELECT outing_record_id AS id, u.customer_name AS customerName, reason AS outingReason, outing_date AS outingDate, expected_return_date AS returnDate, real_return_date AS actualReturnDate, accompany AS companion, relationship, accompany_tel AS companionPhone, Case status when '0' then '通过' when '1' then '未通过' when '2' then '已提交' when '3' then '未提交' when '4' then '已撤销' end AS approvalStatus FROM outing_record c Left Join customer u ON c.customer_id = u.customer_id
c.user_id=#{userId}
AND c.customer_name LIKE CONCAT('%', #{customerName}, '%')
AND c.del_flag = '0'
ORDER BY c.outing_record_id DESC LIMIT #{pageStart}, #{pageSize}

mapper.update:
UPDATE outing_record
SET real_return_date = #{actualReturnDate}
WHERE outing_record_id = #{id}
AND del_flag = '0'
